    for (long long i = 1; i <= n; i *= 2) {
        q.push(i);
        depth[i] = 1;
    }

    // BFS to compute depth for all numbers
    while (!q.empty()) {
        long long x = q.front();
        q.pop();
        long long next = __builtin_popcount(x);
        if (depth[next] == -1) {
            depth[next] = depth[x] + 1;
            q.push(next);
        }
    }

    // Count numbers with popcount-depth exactly equal to k
    long long count = 0;
    for (long long i = 1; i <= n; ++i) {
        if (depth[i] == k) {
            ++count;
        }
    }
    return count;
}

